1	// game-of-life.ts
2	export type Cell = [number, number];
3	
4	export const nextGeneration = (liveCells: Cell[]): Cell[] =>
5	  candidates(liveCells).filter(
6	    (cell) => countLiveNeighbors(cell, liveCells) === 3
7	  );
8	
9	const candidates = (liveCells: Cell[]): Cell[] => {
10	  const all = liveCells.flatMap((cell) => [cell, ...neighborsOf(cell)]);
11	  return all.filter(
12	    (cell, index) =>
13	      all.findIndex((other) => isSamePosition(other, cell)) === index
14	  );
15	};
16	
17	const neighborsOf = ([x, y]: Cell): Cell[] =>
18	  [-1, 0, 1].flatMap((dx) =>
19	    [-1, 0, 1]
20	      .filter((dy) => !(dx === 0 && dy === 0))
21	      .map((dy): Cell => [x + dx, y + dy])
22	  );
23	
24	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
25	  neighborsOf(cell).filter((neighbor) => isAlive(neighbor, liveCells)).length;
26	
27	const isAlive = (cell: Cell, liveCells: Cell[]): boolean =>
28	  liveCells.some((liveCell) => isSamePosition(liveCell, cell));
29	
30	const isSamePosition = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
31	  ax === bx && ay === by;
